+
+        // Cache should not report issues for small cache
+        let cache_issues: Vec<_> = report
+            .issues
+            .iter()
+            .filter(|i| matches!(i.mode, FailureMode::Cache))
+            .collect();
+
+        // Small cache = no issues
+        assert!(
+            cache_issues.is_empty(),
+            "small cache should not trigger warnings"
+        );
+    }
